   976 |                                                  ZExtInst &Zext) {
   977 |   // If we are just checking for a icmp eq of a single bit and zext'ing it
   978 |   // to an integer, then shift the bit to the appropriate place and then
   979 |   // cast to integer to avoid the comparison.
